changeSet.sql:
UPDATE stat_types SET name = 'Strength',     description = 'Physical power'          WHERE id = 'a0000000-0000-0000-0000-000000000001';
UPDATE stat_types SET name = 'Dexterity',    description = 'Agility and reflexes'     WHERE id = 'a0000000-0000-0000-0000-000000000002';
UPDATE stat_types SET name = 'Constitution', description = 'Endurance and health'     WHERE id = 'a0000000-0000-0000-0000-000000000003';
UPDATE stat_types SET name = 'Intelligence', description = 'Logic and memory'         WHERE id = 'a0000000-0000-0000-0000-000000000004';
UPDATE stat_types SET name = 'Wisdom',       description = 'Perception and insight'   WHERE id = 'a0000000-0000-0000-0000-000000000005';
UPDATE stat_types SET name = 'Charisma',     description = 'Force of personality'     WHERE id = 'a0000000-0000-0000-0000-000000000006';

UPDATE character_classes SET name = 'Fighter',  description = 'A master of martial combat, skilled with a variety of weapons and armor' WHERE id = 'b0000000-0000-0000-0000-000000000001';
UPDATE character_classes SET name = 'Wizard',   description = 'A scholarly magic-user capable of manipulating the structures of reality' WHERE id = 'b0000000-0000-0000-0000-000000000002';
UPDATE character_classes SET name = 'Rogue',    description = 'A scoundrel who uses stealth and trickery to overcome obstacles' WHERE id = 'b0000000-0000-0000-0000-000000000003';
UPDATE character_classes SET name = 'Cleric',   description = 'A priestly champion who wields divine magic in service of a higher power' WHERE id = 'b0000000-0000-0000-0000-000000000004';
UPDATE character_classes SET name = 'Ranger',   description = 'A warrior who combats threats on the edges of civilization' WHERE id = 'b0000000-0000-0000-0000-000000000005';
UPDATE character_classes SET name = 'Paladin',  description = 'A holy warrior bound to a sacred oath' WHERE id = 'b0000000-0000-0000-0000-000000000006';
UPDATE character_classes SET name = 'Bard',     description = 'An inspiring magician whose power echoes the music of creation' WHERE id = 'b0000000-0000-0000-0000-000000000007';
UPDATE character_classes SET name = 'Druid',    description = 'A priest of the Old Faith, wielding the powers of nature' WHERE id = 'b0000000-0000-0000-0000-000000000008';

INSERT INTO character_classes (id, name, description)
VALUES
    ('b0000000-0000-0000-0000-000000000009', 'Barbarian', 'A fierce warrior of primitive background who can enter a battle rage'),
    ('b0000000-0000-0000-0000-000000000010', 'Monk',      'A master of martial arts, harnessing the power of the body in pursuit of perfection'),
    ('b0000000-0000-0000-0000-000000000011', 'Sorcerer',  'A spellcaster who draws on inherent magic from a gift or bloodline'),
    ('b0000000-0000-0000-0000-000000000012', 'Warlock',   'A wielder of magic derived from a bargain with an extraplanar entity')
ON CONFLICT (name) DO NOTHING;

UPDATE buffs_debuffs SET target_stat_id = (SELECT id FROM stat_types WHERE name = 'Strength')
WHERE name = 'Blessed' AND target_stat_id IS NULL;

UPDATE buffs_debuffs SET target_stat_id = (SELECT id FROM stat_types WHERE name = 'Strength')
WHERE name = 'Weakened' AND target_stat_id IS NULL;

-- Barbarian (new) UPDATE character_classes SET hit_die = 12, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Strength'), saving_throw_stat_ids_json = '["Strength","Constitution"]', skill_choice_count = 2, skill_choice_option_ids_json = '["Animal Handling","Athletics","Intimidation","Nature","Perception","Survival"]', armor_weapon_proficiencies = 'Light armor, medium armor, shields, simple weapons, martial weapons', is_spellcaster = false, has_cantrips = false, is_half_caster = false WHERE name = 'Barbarian';
-- Bard UPDATE character_classes SET hit_die = 8, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Charisma'), saving_throw_stat_ids_json = '["Dexterity","Charisma"]', skill_choice_count = 3, skill_choice_option_ids_json = '["Acrobatics","Animal Handling","Arcana","Athletics","Deception","History","Insight","Intimidation","Investigation","Medicine","Nature","Perception","Performance","Persuasion","Religion","Sleight of Hand","Stealth","Survival"]', armor_weapon_proficiencies = 'Light armor, simple weapons, hand crossbows, longswords, rapiers, shortswords', is_spellcaster = true, spellcasting_stat_id = (SELECT id FROM stat_types WHERE name = 'Charisma'), has_cantrips = true, is_half_caster = false WHERE name = 'Bard';
-- Cleric UPDATE character_classes SET hit_die = 8, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Wisdom'), saving_throw_stat_ids_json = '["Wisdom","Charisma"]', skill_choice_count = 2, skill_choice_option_ids_json = '["History","Insight","Medicine","Persuasion","Religion"]', armor_weapon_proficiencies = 'Light armor, medium armor, shields, simple weapons', is_spellcaster = true, spellcasting_stat_id = (SELECT id FROM stat_types WHERE name = 'Wisdom'), has_cantrips = true, is_half_caster = false WHERE name = 'Cleric';
-- Druid UPDATE character_classes SET hit_die = 8, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Wisdom'), saving_throw_stat_ids_json = '["Intelligence","Wisdom"]', skill_choice_count = 2, skill_choice_option_ids_json = '["Arcana","Animal Handling","Insight","Medicine","Nature","Perception","Religion","Survival"]', armor_weapon_proficiencies = 'Light armor, medium armor, shields (nonmetal), clubs, daggers, darts, javelins, maces, quarterstaffs, scimitars, sickles, slings, spears', is_spellcaster = true, spellcasting_stat_id = (SELECT id FROM stat_types WHERE name = 'Wisdom'), has_cantrips = true, is_half_caster = false WHERE name = 'Druid';
-- Fighter UPDATE character_classes SET hit_die = 10, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Strength'), saving_throw_stat_ids_json = '["Strength","Constitution"]', skill_choice_count = 2, skill_choice_option_ids_json = '["Acrobatics","Animal Handling","Athletics","History","Insight","Intimidation","Perception","Survival"]', armor_weapon_proficiencies = 'All armor, shields, simple weapons, martial weapons', is_spellcaster = false, has_cantrips = false, is_half_caster = false WHERE name = 'Fighter';
-- Monk (new) UPDATE character_classes SET hit_die = 8, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Dexterity'), saving_throw_stat_ids_json = '["Strength","Dexterity"]', skill_choice_count = 2, skill_choice_option_ids_json = '["Acrobatics","Athletics","History","Insight","Religion","Stealth"]', armor_weapon_proficiencies = 'Simple weapons, shortswords', is_spellcaster = false, has_cantrips = false, is_half_caster = false WHERE name = 'Monk';
-- Paladin UPDATE character_classes SET hit_die = 10, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Strength'), saving_throw_stat_ids_json = '["Wisdom","Charisma"]', skill_choice_count = 2, skill_choice_option_ids_json = '["Athletics","Insight","Intimidation","Medicine","Persuasion","Religion"]', armor_weapon_proficiencies = 'All armor, shields, simple weapons, martial weapons', is_spellcaster = true, spellcasting_stat_id = (SELECT id FROM stat_types WHERE name = 'Charisma'), has_cantrips = false, is_half_caster = true WHERE name = 'Paladin';
-- Ranger UPDATE character_classes SET hit_die = 10, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Dexterity'), saving_throw_stat_ids_json = '["Strength","Dexterity"]', skill_choice_count = 3, skill_choice_option_ids_json = '["Animal Handling","Athletics","Insight","Investigation","Nature","Perception","Stealth","Survival"]', armor_weapon_proficiencies = 'Light armor, medium armor, shields, simple weapons, martial weapons', is_spellcaster = true, spellcasting_stat_id = (SELECT id FROM stat_types WHERE name = 'Wisdom'), has_cantrips = false, is_half_caster = true WHERE name = 'Ranger';
-- Rogue UPDATE character_classes SET hit_die = 8, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Dexterity'), saving_throw_stat_ids_json = '["Dexterity","Intelligence"]', skill_choice_count = 4, skill_choice_option_ids_json = '["Acrobatics","Athletics","Deception","Insight","Intimidation","Investigation","Perception","Performance","Persuasion","Sleight of Hand","Stealth"]', armor_weapon_proficiencies = 'Light armor, simple weapons, hand crossbows, longswords, rapiers, shortswords', is_spellcaster = false, has_cantrips = false, is_half_caster = false WHERE name = 'Rogue';
-- Sorcerer (new) UPDATE character_classes SET hit_die = 6, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Charisma'), saving_throw_stat_ids_json = '["Constitution","Charisma"]', skill_choice_count = 2, skill_choice_option_ids_json = '["Arcana","Deception","Insight","Intimidation","Persuasion","Religion"]', armor_weapon_proficiencies = 'Daggers, darts, slings, quarterstaffs, light crossbows', is_spellcaster = true, spellcasting_stat_id = (SELECT id FROM stat_types WHERE name = 'Charisma'), has_cantrips = true, is_half_caster = false WHERE name = 'Sorcerer';
-- Warlock (new) UPDATE character_classes SET hit_die = 8, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Charisma'), saving_throw_stat_ids_json = '["Wisdom","Charisma"]', skill_choice_count = 2, skill_choice_option_ids_json = '["Arcana","Deception","History","Intimidation","Investigation","Nature","Religion"]', armor_weapon_proficiencies = 'Light armor, simple weapons', is_spellcaster = true, spellcasting_stat_id = (SELECT id FROM stat_types WHERE name = 'Charisma'), has_cantrips = true, is_half_caster = false WHERE name = 'Warlock';
-- Wizard UPDATE character_classes SET hit_die = 6, primary_ability_stat_id = (SELECT id FROM stat_types WHERE name = 'Intelligence'), saving_throw_stat_ids_json = '["Intelligence","Wisdom"]', skill_choice_count = 2, skill_choice_option_ids_json = '["Arcana","History","Insight","Investigation","Medicine","Religion"]', armor_weapon_proficiencies = 'Daggers, darts, slings, quarterstaffs, light crossbows', is_spellcaster = true, spellcasting_stat_id = (SELECT id FROM stat_types WHERE name = 'Intelligence'), has_cantrips = true, is_half_caster = false WHERE name = 'Wizard';
